FROM jsonb_to_recordset('[{"id": "cap-114-english-reading-001", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Look at the picture. A         is flying over the houses.", "options": ["bird", "butterfly", "kite", "plane"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 1, "raw_text": "1.   Look at the picture. A         is flying over the houses.\n     (A) bird\n     (B) butterfly\n     (C) kite\n     (D) plane\n\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "圖片中飛行於房屋上方的物品，依題幹「flying over the houses」+ 一般日常常見最合理的是「a plane（飛機）」，故 (D) 正確。bird、butterfly 雖能飛但不會被一般描述為「houses」上方意象的主體；kite 通常綁線且需強調「fly a kite」。"}, {"id": "cap-114-english-reading-002", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "When I was a teenager, I was very          .  But now, it’s easier for me to talk to people.", "options": ["happy", "lazy", "popular", "shy"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 2, "raw_text": "2. \t When I was a teenager, I was very          .  But now, it’s easier for me to talk to people.\n     (A) happy            (B) lazy                 (C) popular             (D) shy\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "上下文「現在我比較容易跟人講話」反推青少年期的相反狀態，「shy（害羞）」最切合，故 (D) 正確。(A) happy 與「easier to talk to people」無對立；(B) lazy、(C) popular 都無法解釋現在反而較易交流。"}, {"id": "cap-114-english-reading-003", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Lena doesn’t want to go         with John because she is afraid of water.", "options": ["dancing", "hiking", "sailing", "shopping"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 3, "raw_text": "3. \t Lena doesn’t want to go         with John because she is afraid of water.\n     (A) dancing           (B) hiking            (C) sailing            (D) shopping\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "「她怕水（afraid of water）」對應的水上活動是「sailing（駕船）」，故 (C) 正確。(A) dancing、(B) hiking、(D) shopping 與水無關。"}, {"id": "cap-114-english-reading-004", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Cindy enjoys         her dad read stories to her before bed.", "options": ["to listen to", "listening to", "listen to", "listens to"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 4, "raw_text": "4. \t Cindy enjoys         her dad read stories to her before bed.\n     (A) to listen to      (B) listening to        (C) listen to           (D) listens to\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "「enjoy + V-ing」是固定搭配，故 (B) listening to 正確。(A) to listen to 為不定詞、(C) listen to 為原型、(D) listens to 為第三人稱單數，皆不合 enjoy 後接動名詞的文法規則。"}, {"id": "cap-114-english-reading-005", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Dad is busy cooking in the kitchen.  Dinner will be            in ten minutes.", "options": ["free", "full", "medium", "ready"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 5, "raw_text": "5. \t Dad is busy cooking in the kitchen.  Dinner will be            in ten minutes.\n     (A) free             (B) full               (C) medium                 (D) ready\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "Dad 正在廚房煮飯、十分鐘後晚餐將「準備好」，「ready」最切合，故 (D) 正確。(A) free（免費的）、(B) full（飽的）、(C) medium（中等）皆與「即將上桌」語意不合。"}, {"id": "cap-114-english-reading-006", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "There are so many new          in the office.  It’ll take me some time to remember who is\nwho.", "options": ["faces", "ideas", "rules", "tools"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 6, "raw_text": "6. \t There are so many new          in the office.  It’ll take me some time to remember who is\n     who.\n     (A) faces            (B) ideas                (C) rules              (D) tools\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "辦公室裡許多新來的事物 + 需要時間記住誰是誰，最合理的是新「faces（面孔/同事）」，故 (A) 正確。(B) ideas、(C) rules、(D) tools 與「記住誰是誰」無對應。"}, {"id": "cap-114-english-reading-007", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "I feel like a       .  I was looking for my keys for hours but they have been in my pocket\nthe whole time.", "options": ["fool", "ghost", "king", "stranger"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 7, "raw_text": "7. \t I feel like a       .  I was looking for my keys for hours but they have been in my pocket\n     the whole time.\n     (A) fool               (B) ghost               (C) king               (D) stranger\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "找鑰匙找了好幾小時、結果一直在自己口袋裡，最符合「I feel like a fool（覺得自己像個笨蛋）」的情境，故 (A) 正確。(B) ghost、(C) king、(D) stranger 都不符合自嘲糊塗的語意。"}, {"id": "cap-114-english-reading-008", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Mr. and Mrs. Wu have three daughters.  Two are in high school, and        is in\nelementary school.", "options": ["each", "the other", "the one", "the next"], "correct_answer": 1, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 8, "raw_text": "8. \t Mr. and Mrs. Wu have three daughters.  Two are in high school, and        is in\n     elementary school.\n     (A) each           (B) the other        (C) the one          (D) the next\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "三個女兒，「Two are…and the other is…」是「三者中其餘一個」的固定用法，故 (B) the other 正確。(A) each 用於整體一一指；(C) the one 缺乏對比；(D) the next 表「下一個」非「剩下那一個」。"}, {"id": "cap-114-english-reading-009", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "It is hard for trees to       along this beach because of the strong winds from the sea.", "options": ["blow", "build", "follow", "grow"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 9, "raw_text": "9. \t It is hard for trees to       along this beach because of the strong winds from the sea.\n     (A) blow                (B) build             (C) follow             (D) grow\n\n\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "強風使樹木難以「生長（grow）」於海邊，故 (D) 正確。(A) blow 是風的動作；(B) build 不用於樹；(C) follow 與樹無關。"}, {"id": "cap-114-english-reading-010", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Christmas            and I want to visit my aunt abroad.  Do you have any plans yet?", "options": ["came", "comes", "is coming", "was coming"], "correct_answer": 2, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 10, "raw_text": "10. Christmas            and I want to visit my aunt abroad.  Do you have any plans yet?\n    (A) came                (B) comes              (C) is coming         (D) was coming\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "「Christmas is coming」表示聖誕節即將到來，搭配下文「我想去拜訪阿姨」屬計劃中事件，現在進行式表近未來最自然，故 (C) 正確。(A)(B)(D) 時態不符「即將到來且尚在計畫中」的語境。"}, {"id": "cap-114-english-reading-011", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "Jo won’t be happy if you’re late for his party tonight, so      sure that you arrive on time.", "options": ["make", "makes", "to make", "is making"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 11, "raw_text": "11.   Jo won’t be happy if you’re late for his party tonight, so      sure that you arrive on time.  \n      (A) make              (B) makes                (C) to make          (D) is making\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "前句已用助動詞 won''t 假設條件、後句以對等連接 so 接祈使句「make sure that you arrive on time」，動詞應用原型，故 (A) make 正確。(B)(C)(D) 形式皆不符祈使句結構。"}, {"id": "cap-114-english-reading-012", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "You may have a long drive because of the terrible       .  There are usually a lot of cars\nand buses during this time.", "options": ["experience", "machine", "service", "traffic"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 12, "raw_text": "12. You may have a long drive because of the terrible       .  There are usually a lot of cars\n    and buses during this time.\n    (A) experience         (B) machine          (C) service           (D) traffic\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "「a long drive because of the terrible…」+「a lot of cars and buses」兩條線索都指向交通問題，故 (D) traffic 正確。(A) experience、(B) machine、(C) service 皆無法搭配「因 X 而開很久的車」。"}, {"id": "cap-114-english-reading-013", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "In the future, there will         be greater basketball players than Stephen Curry, but now\nwe believe he is the best!", "options": ["again", "already", "never", "perhaps"], "correct_answer": 3, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 13, "raw_text": "13. In the future, there will         be greater basketball players than Stephen Curry, but now\n    we believe he is the best!\n    (A) again               (B) already            (C) never              (D) perhaps\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "句意「未來會有更偉大的球員，但現在我們相信他是最棒的」，前句用助動詞 will + 副詞，「perhaps（也許）」表示可能性，最切合「未來不確定但現在認定」的語氣，故 (D) 正確。(A) again、(B) already、(C) never 都不合上下文邏輯。"}, {"id": "cap-114-english-reading-014", "exam_id": "cap", "subject_id": "sub-cap-english-reading", "paper_id": "cap-114-english-reading", "question_type": "single_choice", "question_text": "I guess the rainwater has come in from the kitchen.  See?           of the windows are closed\nexcept the one in the kitchen.", "options": ["All", "Both", "Most", "Some"], "correct_answer": 0, "correct_answer_json": null, "parent_question_id": null, "media": null, "source": "official", "source_meta": {"parser_version": "cap_v0.1", "merger_version": "cap_merger_v0.2", "parsed_at": "2026-04-25T18:39:39+00:00", "source_pdf_sha1": "dec9486b85ec", "answer_pdf_sha1": "6a98d676c5b0", "flags": [], "parse_confidence": 1.0, "original_question_number": 14, "raw_text": "14. I guess the rainwater has come in from the kitchen.  See?           of the windows are closed\n    except the one in the kitchen.\n    (A) All                (B) Both              (C) Most                 (D) Some\n", "explanation_source": "ai_v1_inline"}, "is_active": true, "auto_gradable": true, "difficulty": 3, "explanation": "下文「除了廚房那扇」即所有窗戶都關了，「All of the windows are closed except the one」最自然，故 (A) All 正確。(B) Both 限兩扇；(C) Most 不能搭配 except + 單一窗戶；(D) Some 與「除了一扇外都關」邏輯不合。"}]'::jsonb) AS t(
